func (a *adapter) Create(ctx context.Context, input subject.CreateInput) (subject.Subject, error) {
  if err := input.Validate(); err != nil {
    return subject.Subject{}, fmt.Errorf("invalid input: %w", models.NewGenericValidationError(err))
  }
  return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *adapter) (subject.Subject, error) {
    e, err := tx.db.Subject.Create().SetNamespace(input.Namespace).SetKey(input.Key).Save(ctx)
    if err != nil {
      if db.IsConstraintError(err) {
        return subject.Subject{}, models.NewGenericConflictError(fmt.Errorf("subject with key already exists: %s", input.Key))
      }
      return subject.Subject{}, fmt.Errorf("failed to create subject: %w", err)
    }
    return mapEntity(e), nil
  })
}

func (h *handler) GetSubject() GetSubjectHandler {
  return httptransport.NewHandlerWithArgs(
    func(ctx context.Context, r *http.Request, idOrKey GetSubjectParams) (GetSubjectRequest, error) {
      ns, err := h.resolveNamespace(ctx)
      if err != nil { return GetSubjectRequest{}, err }
      return GetSubjectRequest{namespace: ns, subjectIdOrKey: idOrKey}, nil
    },
    func(ctx context.Context, req GetSubjectRequest) (GetSubjectResponse, error) {
      sub, err := h.subjectService.GetByIdOrKey(ctx, req.namespace, req.subjectIdOrKey)
      if err != nil { return GetSubjectResponse{}, fmt.Errorf("failed to get subject: %w", err) }
      return FromSubject(sub), nil
    },
    commonhttp.JSONResponseEncoderWithStatus[GetSubjectResponse](http.StatusOK),
    httptransport.AppendOptions(h.options, httptransport.WithOperationName("getSubject"))...,
  )
}

func NewTestEnv(t *testing.T) *TestEnv {
  logger := testutils.NewDiscardLogger(t)
  db := testutils.InitPostgresDB(t)
  client := db.EntDriver.Client()
  subjectAdapter, err := subjectadapter.New(client)
  require.NoError(t, err)
  subjectService, err := subjectservice.New(subjectAdapter)
  require.NoError(t, err)
  return &TestEnv{SubjectService: subjectService, Client: client, db: db, close: sync.Once{}}
}
